47	    /** @type {typeof Processor.from_pretrained} */
48	    static async from_pretrained(pretrained_model_name_or_path, options={}) {
49	
50	        // TODO: first check for processor.json 
51	        const preprocessorConfig = await getModelJSON(pretrained_model_name_or_path, IMAGE_PROCESSOR_NAME, true, options);
52	
53	        const { image_processor_type, feature_extractor_type, processor_class } = preprocessorConfig;
54	        if (processor_class && AllProcessors[processor_class]) {
55	            return AllProcessors[processor_class].from_pretrained(pretrained_model_name_or_path, options);
56	        }
57	
58	        if (!image_processor_type && !feature_extractor_type) {
59	            throw new Error('No `image_processor_type` or `feature_extractor_type` found in the config.');
60	        }
61	
62	        const components = {};
63	        if (image_processor_type) {
64	            // Some image processors are saved with the "Fast" suffix, so we remove that if present.
65	            const image_processor_class = AllImageProcessors[image_processor_type.replace(/Fast$/, '')];
66	            if (!image_processor_class) {
67	                throw new Error(`Unknown image_processor_type: '${image_processor_type}'.`);
68	            }
69	            components.image_processor = new image_processor_class(preprocessorConfig);
70	        }
71	
72	        if (feature_extractor_type) {
73	            const image_processor_class = AllImageProcessors[feature_extractor_type];
74	            if (image_processor_class) {
75	                // Handle legacy case where image processors were specified as feature extractors
76	                components.image_processor = new image_processor_class(preprocessorConfig);
77	            } else {
