25	/**
26	 * Helper function to constrain a value to be a multiple of a number.
27	 * @param {number} val The value to constrain.
28	 * @param {number} multiple The number to constrain to.
29	 * @param {number} [minVal=0] The minimum value to constrain to.
30	 * @param {number} [maxVal=null] The maximum value to constrain to.
31	 * @returns {number} The constrained value.
32	 * @private
33	 */
34	function constraint_to_multiple_of(val, multiple, minVal = 0, maxVal = null) {
35	    const a = val / multiple;
36	    let x = bankers_round(a) * multiple;
37	
38	    if (maxVal !== null && x > maxVal) {
39	        x = Math.floor(a) * multiple;
40	    }
41	
42	    if (x < minVal) {
43	        x = Math.ceil(a) * multiple;
44	    }
45	
46	    return x;
47	}
