51	 * @param {[number, number]} size The size of the image
52	 * @param {number} divisor The divisor to use.
53	 * @returns {[number, number]} The rounded size.
54	 */
55	function enforce_size_divisibility([width, height], divisor) {
56	    return [
57	        Math.max(Math.floor(width / divisor), 1) * divisor,
58	        Math.max(Math.floor(height / divisor), 1) * divisor
59	    ];
