90	export function post_process_object_detection(outputs, threshold = 0.5, target_sizes = null, is_zero_shot = false) {
91	    const out_logits = outputs.logits;
92	    const out_bbox = outputs.pred_boxes;
93	    const [batch_size, num_boxes, num_classes] = out_logits.dims;
94	
95	    if (target_sizes !== null && target_sizes.length !== batch_size) {
96	        throw Error("Make sure that you pass in as many target sizes as the batch dimension of the logits")
97	    }
98	    let toReturn = [];
99	    for (let i = 0; i < batch_size; ++i) {
100	        let target_size = target_sizes !== null ? target_sizes[i] : null;
101	        let info = {
102	            boxes: [],
103	            classes: [],
104	            scores: []
105	        }
106	        let logits = out_logits[i];
107	        let bbox = out_bbox[i];
108	
109	        for (let j = 0; j < num_boxes; ++j) {
110	            let logit = logits[j];
111	
112	            let indices = [];
113	            let probs;
114	            if (is_zero_shot) {
115	                // Get indices of classes with high enough probability
116	                probs = logit.sigmoid().data;
117	                for (let k = 0; k < probs.length; ++k) {
118	                    if (probs[k] > threshold) {
119	                        indices.push(k);
120	                    }
121	                }
122	
123	            } else {
124	                // Get most probable class
125	                let maxIndex = max(logit.data)[1];
126	
127	                if (maxIndex === num_classes - 1) {
128	                    // This is the background class, skip it
129	                    continue;
130	                }
131	                // Compute softmax over classes
132	                probs = softmax(logit.data);
133	
134	                if (probs[maxIndex] < threshold) {
135	                    continue;
136	                }
137	                indices.push(maxIndex);
138	            }
139	
140	            for (const index of indices) {
141	
142	                // Some class has a high enough probability
143	                /** @type {number[]} */
144	                let box = bbox[j].data;
145	
146	                // convert to [x0, y0, x1, y1] format
147	                box = center_to_corners_format(box)
148	                if (target_size !== null) {
149	                    box = box.map((x, i) => x * target_size[(i + 1) % 2])
150	                }
151	
152	                info.boxes.push(box);
153	                info.classes.push(index);
154	                info.scores.push(probs[index]);
155	            }
156	        }
157	        toReturn.push(info);
158	    }
159	    return toReturn;
