168	 * @returns {{segmentation: Tensor; labels: number[]}[]} The semantic segmentation maps.
169	 */
170	export function post_process_semantic_segmentation(outputs, target_sizes = null) {
171	
172	    const logits = outputs.logits;
173	    const batch_size = logits.dims[0];
174	
175	    if (target_sizes !== null && target_sizes.length !== batch_size) {
176	        throw Error("Make sure that you pass in as many target sizes as the batch dimension of the logits")
177	    }
178	
179	    const toReturn = [];
180	    for (let i = 0; i < batch_size; ++i) {
181	        const target_size = target_sizes !== null ? target_sizes[i] : null;
182	
183	        let data = logits[i];
184	
185	        // 1. If target_size is not null, we need to resize the masks to the target size
186	        if (target_size !== null) {
187	            // resize the masks to the target size
188	            data = interpolate(data, target_size, 'bilinear', false);
189	        }
190	        const [height, width] = target_size ?? data.dims.slice(-2);
191	
192	        const segmentation = new Tensor(
193	            'int32',
194	            new Int32Array(height * width),
195	            [height, width]
196	        );
197	
198	        // Buffer to store current largest value
199	        const buffer = data[0].data;
200	        const segmentation_data = segmentation.data;
201	        for (let j = 1; j < data.dims[0]; ++j) {
202	            const row = data[j].data;
203	            for (let k = 0; k < row.length; ++k) {
204	                if (row[k] > buffer[k]) {
205	                    buffer[k] = row[k];
206	                    segmentation_data[k] = j;
207	                }
208	            }
209	        }
210	
211	        // Store which objects have labels
212	        // This is much more efficient that creating a set of the final values
213	        const hasLabel = new Array(data.dims[0]);
214	        for (let j = 0; j < segmentation_data.length; ++j) {
215	            const index = segmentation_data[j];
216	            hasLabel[index] = index;
217	        }
218	        /** @type {number[]} The unique list of labels that were detected */
219	        const labels = hasLabel.filter(x => x !== undefined);
220	
221	        toReturn.push({ segmentation, labels });
222	    }
223	    return toReturn;
