236	function remove_low_and_no_objects(class_logits, mask_logits, object_mask_threshold, num_labels) {
237	
238	    const mask_probs_item = [];
239	    const pred_scores_item = [];
240	    const pred_labels_item = [];
241	
242	    for (let j = 0; j < class_logits.dims[0]; ++j) {
243	        const cls = class_logits[j];
244	        const mask = mask_logits[j];
245	
246	        const pred_label = max(cls.data)[1];
247	        if (pred_label === num_labels) {
248	            // Is the background, so we ignore it
249	            continue;
250	        }
251	
252	        const scores = softmax(cls.data);
253	        const pred_score = scores[pred_label];
254	        if (pred_score > object_mask_threshold) {
255	            mask_probs_item.push(mask);
256	            pred_scores_item.push(pred_score);
257	            pred_labels_item.push(pred_label);
258	        }
259	    }
260	
261	    return [mask_probs_item, pred_scores_item, pred_labels_item];
